export interface Dish {
  id: number;
  name: string;
  country: string;
  flag: string;
  description: string;
  taste: string;
  method: string;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
}

export type LocaleText = { en: string; zh: string; es: string; fr: string; de: string; ja: string; ko: string };

export interface DishI18n {
  id: number;
  name: LocaleText;
  country: LocaleText;
  flag: string;
  description: LocaleText;
  taste: LocaleText;
  method: LocaleText;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
}

export function getLocalizedDish(dish: DishI18n, locale: string): Dish {
  const loc = (locale in dish.name) ? locale : "en";
  return {
    id: dish.id,
    name: dish.name[loc as keyof LocaleText] || dish.name.en,
    country: dish.country[loc as keyof LocaleText] || dish.country.en,
    flag: dish.flag,
    description: dish.description[loc as keyof LocaleText] || dish.description.en,
    taste: dish.taste[loc as keyof LocaleText] || dish.taste.en,
    method: dish.method[loc as keyof LocaleText] || dish.method.en,
    calories: dish.calories,
    protein: dish.protein,
    carbs: dish.carbs,
    fat: dish.fat,
  };
}

